import { describe, it, expect } from 'vitest';
import { HologramNavigator } from './hologram-navigator';
import { encodeCsvHologram } from './data-hologram';
import { BettyCompiler } from './compiler';
import { executeHologramQuery } from './hologram-query';

describe('Topological Raycaster & Schubert Slicing', () => {
  const csv = [
    'id,name,age',
    '1,Alice,25',
    '2,Bob,35',
    '3,Charlie,40',
    '4,David,28',
  ].join('\\n');

  const hologram = encodeCsvHologram(csv);

  it('should project an affine coordinate in O(1) time', () => {
    const nav = new HologramNavigator(hologram);
    // Row 2 is "3,Charlie,40"
    // Col 1 is "Charlie"
    const val = nav.projectAffine(2, 1);
    expect(val).toBe('Charlie');
  });

  it('should throw out-of-bounds on invalid affine projections', () => {
    const nav = new HologramNavigator(hologram);
    expect(() => nav.projectAffine(10, 0)).toThrow(/exceeds static volume/);
    expect(() => nav.projectAffine(0, 5)).toThrow(/exceeds dimensionality/);
  });

  it('should intersect Schubert cells to filter a subset tensor', () => {
    const nav = new HologramNavigator(hologram);

    // Query: SELECT * WHERE col 2 (age) > 30
    const subset = nav.intersectSchubert((val, colIndex) => {
      return colIndex === 2 && Number(val) > 30;
    });

    expect(subset.geometry.dimensionality).toBe(3); // k stays 3
    expect(subset.geometry.staticVolume).toBe(6); // 2 matching rows * 3 cols = 6 cells
    expect(subset.ventDictionary).toEqual([
      '2',
      'Bob',
      '35',
      '3',
      'Charlie',
      '40',
    ]);
  });

  it('should execute a .gg Schubert Query via BettyCompiler', () => {
    const querySrc = `
(source:Hologram)
(source)-[:OBSERVE {row: 1, col: 1}]->(cell)
(source)-[:SLIVER {col: 2, operator: ">", value: 30}]->(subset)
    `;

    const compiler = new BettyCompiler();
    const queryAst = compiler.parse(querySrc).ast!;

    const results = executeHologramQuery(queryAst, hologram);

    expect(results).toHaveLength(2);
    expect(results[0]!.type).toBe('AFFINE_SCALAR');
    expect(results[0]!.scalar).toBe('Alice'); // row 1, col 1

    expect(results[1]!.type).toBe('SCHUBERT_SUBSET');
    expect(results[1]!.subset!.ventDictionary).toEqual([
      '2',
      'Bob',
      '35',
      '3',
      'Charlie',
      '40',
    ]);
  });
});
